import { useEffect, useState } from "react";
import Header from "./Header";

export default function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [matches, setMatches] = useState([]);
    const [events, setEvents] = useState([]);

    useEffect(() => {
        fetch("/api/threads").then(r=>r.json()).then(setThreads);
        fetch("/api/news").then(r=>r.json()).then(setNews);
        fetch("/api/matches").then(r=>r.json()).then(setMatches);
        fetch("/api/events").then(r=>r.json()).then(setEvents);
    }, []);

    return (
        <div>
            <Header />
            <div style={{ display:"flex", gap:20, padding:20 }}>
                <div style={{flex:1}}>
                    <h3>Threads</h3>
                    <ul>{threads.map(t => <li key={t.id}>{t.title}</li>)}</ul>
                </div>
                <div style={{flex:1}}>
                    <h3>News</h3>
                    <ul>{news.map(n => <li key={n.id}>{n.headline}</li>)}</ul>
                </div>
                <div style={{flex:1}}>
                    <h3>Matches</h3>
                    <ul>{matches.map(m => (
                        <li key={m.id}>
                            {m.teamA} vs {m.teamB} — {new Date(m.matchTime).toLocaleString()}
                        </li>
                    ))}</ul>
                </div>
                <div style={{flex:1}}>
                    <h3>Events</h3>
                    <ul>{events.map(e => (
                        <li key={e.id}>
                            {e.name} — {new Date(e.eventDateTime).toLocaleString()}
                        </li>
                    ))}</ul>
                </div>
            </div>
        </div>
    );
}
